local discordLink = "https://discord.gg/QeKmyDA9d7"
local COOLDOWN_FILE = "miwahub_discord_cooldown.txt"
local COOLDOWN_DURATION = 86400 -- 24 hours in seconds

local function handleDiscordInvite()
    if not isfile or not readfile or not writefile then return end
    
    local needsInvite = true
    
    if isfile(COOLDOWN_FILE) then
        local success, savedTime = pcall(readfile, COOLDOWN_FILE)
        if success and tonumber(savedTime) then
            local timePassed = os.time() - tonumber(savedTime)
            if timePassed < COOLDOWN_DURATION then
                needsInvite = false
            end
        end
    end

  if needsInvite then
        pcall(writefile, COOLDOWN_FILE, tostring(os.time()))
        task.spawn(function()
            if openurl then
                pcall(function() openurl(discordLink) end)
            elseif fluxus and fluxus.openurl then
                pcall(function() fluxus.openurl(discordLink) end)
            elseif syn and syn.openurl then
                pcall(function() syn.openurl(discordLink) end)
            end

            if setclipboard or toclipboard then
                pcall(function()
                    if setclipboard then setclipboard(discordLink) else toclipboard(discordLink) end
                end)
            end
        
        pcall(function()
                game:GetService("StarterGui"):SetCore("SendNotification", {
                    Title = "Miwa Hub",
                    Text = "Opening Discord Invite... Loading script...",
                    Duration = 4
                })
            end)
        end)
    else

    task.spawn(function()
            pcall(function()
                game:GetService("StarterGui"):SetCore("SendNotification", {
                    Title = "Miwa Hub",
                    Text = "Welcome back! Loading script...",
                    Duration = 3
                })
            end)
        end)
    end
end
handleDiscordInvite()

